mapper.select:
SELECT dates.dt AS date, COALESCE(c.cnt, 0) AS count, COALESCE(r.cnt, 0) AS reservationCount FROM ( SELECT DATEADD(DAY, -n, CURRENT_DATE) AS dt FROM ( SELECT 0 AS n UNION ALL SELECT 1 UNION ALL SELECT 2 UNION ALL SELECT 3 UNION ALL SELECT 4 UNION ALL SELECT 5 UNION ALL SELECT 6 ) nums WHERE n < #{days} ) dates LEFT JOIN ( SELECT CAST(created_date AS DATE) AS dt, COUNT(*) AS cnt FROM customers WHERE created_date >= DATEADD(DAY, -(#{days} - 1), CURRENT_DATE)
AND branch_seq = #{branchSeq}
GROUP BY CAST(created_date AS DATE) ) c ON dates.dt = c.dt LEFT JOIN ( SELECT CAST(created_date AS DATE) AS dt, COUNT(*) AS cnt FROM reservation_info WHERE created_date >= DATEADD(DAY, -(#{days} - 1), CURRENT_DATE)
AND branch_seq = #{branchSeq}
GROUP BY CAST(created_date AS DATE) ) r ON dates.dt = r.dt ORDER BY dates.dt ASC

SELECT cal.caller, COALESCE(sel.selection_count, 0) AS selectionCount, COALESCE(res.reservation_confirm, 0) AS reservationConfirm, CASE WHEN COALESCE(sel.selection_count, 0) > 0 THEN ROUND(COALESCE(res.reservation_confirm, 0) * 100.0 / sel.selection_count, 2) ELSE 0 END AS confirmRate FROM ( SELECT 'A' AS caller UNION ALL SELECT 'B' UNION ALL SELECT 'C' UNION ALL SELECT 'D' UNION ALL SELECT 'E' UNION ALL SELECT 'F' UNION ALL SELECT 'G' UNION ALL SELECT 'H' UNION ALL SELECT 'I' UNION ALL SELECT 'J' UNION ALL SELECT 'K' UNION ALL SELECT 'L' UNION ALL SELECT 'M' UNION ALL SELECT 'N' UNION ALL SELECT 'O' UNION ALL SELECT 'P' ) cal LEFT JOIN ( SELECT caller, COUNT(*) AS selection_count FROM caller_selection_history WHERE
AND branch_seq = #{branchSeq}
GROUP BY caller ) sel ON cal.caller = sel.caller LEFT JOIN ( SELECT r.caller, COUNT(DISTINCT r.seq) AS reservation_confirm FROM reservation_info r WHERE
AND r.branch_seq = #{branchSeq}
GROUP BY r.caller ) res ON cal.caller = res.caller ORDER BY cal.caller
